arguments.command:
cd /tmp/sv-486cd358930348ebb301fd500d47a884/symbols && \
echo "=== Looking up functions containing those addresses ===" && \
# Get all FUNC symbols sorted by address, find which function range contains these addrs
readelf -sW libmonosgen-2.0.so.dbg 2>/dev/null | awk '$4=="FUNC" && $2!="0000000000000000"' | sort -k2 | awk '{
  val=strtonum("0x"$2); size=strtonum("0x"$3); name=$8;
  if (val <= 0x2f4b20 && val+size > 0x2f4b20) print "0x2f4b20 is in " name " (0x" $2 " + " $3 ")";
  if (val <= 0x2f4c84 && val+size > 0x2f4c84) print "0x2f4c84 is in " name " (0x" $2 " + " $3 ")";
}' && \
echo "=== Checking with -i (inlines) ===" && \
addr2line -C -f -i -e libmonosgen-2.0.so.dbg 0x2f4b20 0x2f4c84 2>&1

